args.sparql:
SELECT ?formerName WHERE {
  ?event wdt:P31 wd:Q286315 ;
         wdt:P17 wd:Q17 ;
         wdt:P131 wd:Q3724 ;
         wdt:P2628 "2000" ;
         rdfs:label ?eventLabel .
  FILTER (CONTAINS(LCASE(?eventLabel), "rugby") && CONTAINS(LCASE(?eventLabel), "championship"))

  ?match wdt:P176 ?event .
  ?match wdt:P1300 ?awayTeam .

  ?awayTeam wdt:P138 ?formerName .
}

